/*
 * test/fixtures/quic_test_pki.h
 *
 * Test-only PKI fixture: an ECDSA P-256 self-signed certificate and the
 * corresponding private key, in DER format, generated offline with:
 *
 *   openssl ecparam -name prime256v1 -genkey -noout -out key.pem
 *   openssl req -x509 -key key.pem -out cert.pem -days 3650 \
 *       -subj "/CN=quic-test.n00b.local"
 *   openssl pkcs8 -in key.pem -topk8 -nocrypt -outform DER -out key.der
 *   openssl x509 -in cert.pem -outform DER -out cert.der
 *
 * Re-generate (e.g. after the cert expires in 2036) with
 * `tools/regenerate_quic_test_pki.sh` (forthcoming).
 *
 * **For unit tests only.**  Production / examples never use these
 * bytes — they go through the dev PKI (see docs/quic/dev_pki.md) or
 * the operator's real PKI.  Self-signed material in the repo is a
 * convenience for the test loopback handshake, deliberately scoped
 * to the test surface.
 *
 * The cert + key are paired via curve P-256.  Algorithm choice is
 * **picotls-minicrypto-driven**, not preference: minicrypto's
 * sign/verify path only ships ECDSA-P-256 (via uECC / micro-ecc).
 * Ed25519 is the broadly preferred modern signature algorithm but is
 * implemented only in picotls's OpenSSL / mbedTLS backends, which we
 * chose not to link in Phase 1 (see docs/quic/vendored.md).  Switching
 * to ed25519 here is a one-line fixture change once we add an
 * OpenSSL- or mbedTLS-backed picotls build option.
 *
 * The cert does not chain to a real CA — verification in tests is via
 * SHA-256 fingerprint pinning (n00b_quic_trust_pinned).
 */
#pragma once
#include <stddef.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <fcntl.h>
#include <sys/stat.h>

/* The key in PEM form too — picotls's minicrypto private-key loader
 * is file-only and reads PEM.  Tests write this string to a temp file
 * and pass the path to the endpoint via the `.key_pem_path` kwarg. */
/* PKCS#8 wrapper (label "PRIVATE KEY", not "EC PRIVATE KEY") because
 * picotls's minicrypto PEM loader matches on the "PRIVATE KEY" label
 * literally — see lib/minicrypto-pem.c:172. */
static const char n00b_quic_test_key_pem[] =
    "-----BEGIN PRIVATE KEY-----\n"
    "MIGHAgEAMBMGByqGSM49AgEGCCqGSM49AwEHBG0wawIBAQQgOdK0nMMd0cKv8kYq\n"
    "xm6f1ZQH1oFoW0a8WrbVtuajDuShRANCAASK/V51sIWTRBsJ1SFKB0p4JMmq7+wd\n"
    "1KUBHqKUHqjnxTd86mWQBBXMg4hR0t1Carh3QhQIZ+IKGzezhWswZ50M\n"
    "-----END PRIVATE KEY-----\n";
static const size_t n00b_quic_test_key_pem_len = sizeof(n00b_quic_test_key_pem) - 1;

/**
 * @brief Write the test key PEM to a freshly created temp file.
 *
 * Caller is responsible for unlinking the path when done.  Returns
 * the path in a heap-allocated string the caller owns (free it).
 *
 * @return Allocated path string, or NULL on failure.
 */
static inline char *
n00b_quic_test_write_key_pem(void)
{
    char tmpl[] = "/tmp/n00b_quic_test_keyXXXXXX.pem";
    int  fd = mkstemps(tmpl, 4);
    if (fd < 0) return NULL;

    ssize_t expected = (ssize_t)n00b_quic_test_key_pem_len;
    ssize_t written  = write(fd, n00b_quic_test_key_pem, n00b_quic_test_key_pem_len);
    close(fd);
    if (written != expected) {
        unlink(tmpl);
        return NULL;
    }
    char *out = (char *)malloc(strlen(tmpl) + 1);
    if (!out) {
        unlink(tmpl);
        return NULL;
    }
    memcpy(out, tmpl, strlen(tmpl) + 1);
    return out;
}

